namespace SiteInspector.Client.Models;

public class Site
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string Name { get; set; } = string.Empty;
    public string Address { get; set; } = string.Empty;
    public DateTime CreatedAt { get; set; } = DateTime.UtcNow;
}

public class Inspection
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string SiteId { get; set; } = string.Empty;
    public string SiteName { get; set; } = string.Empty;
    public DateTime InspectionDate { get; set; } = DateTime.UtcNow;
    public string Notes { get; set; } = string.Empty;
    public List<ChecklistItem> Checklist { get; set; } = new();
    public List<InspectionPhoto> Photos { get; set; } = new();
    public bool IsSynced { get; set; }
    public InspectionStatus Status { get; set; } = InspectionStatus.InProgress;
}

public class ChecklistItem
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public CheckResult Result { get; set; } = CheckResult.NotChecked;
    public string Notes { get; set; } = string.Empty;
}

public class InspectionPhoto
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string FileName { get; set; } = string.Empty;
    public string Base64Data { get; set; } = string.Empty;
    public string Caption { get; set; } = string.Empty;
    public DateTime TakenAt { get; set; } = DateTime.UtcNow;
}

public enum CheckResult
{
    NotChecked,
    Pass,
    Fail,
    NotApplicable
}

public enum InspectionStatus
{
    InProgress,
    Completed
}

using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

/// <summary>
/// Offline-first storage using browser IndexedDB via JS interop.
/// </summary>
public interface ILocalStorageService
{
    Task InitializeAsync();
    Task<List<Site>> GetSitesAsync();
    Task SaveSiteAsync(Site site);
    Task<List<Inspection>> GetInspectionsAsync(string? siteId = null);
    Task<Inspection?> GetInspectionAsync(string id);
    Task SaveInspectionAsync(Inspection inspection);
    Task<List<Inspection>> GetUnsyncedInspectionsAsync();
    Task MarkAsSyncedAsync(string inspectionId);
}

using System.Text.Json;
using Microsoft.JSInterop;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public class IndexedDbStorageService : ILocalStorageService
{
    private readonly IJSRuntime _js;
    private IJSObjectReference? _module;

    public IndexedDbStorageService(IJSRuntime js)
    {
        _js = js;
    }

    private async Task<IJSObjectReference> GetModuleAsync()
    {
        _module ??= await _js.InvokeAsync<IJSObjectReference>(
            "import", "./_content/SiteInspector.Client/js/indexedDb.js");
        return _module;
    }

    public async Task InitializeAsync()
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync("initialize");
    }

    public async Task<List<Site>> GetSitesAsync()
    {
        var module = await GetModuleAsync();
        var json = await module.InvokeAsync<string>("getAll", "sites");
        return JsonSerializer.Deserialize<List<Site>>(json, JsonOptions) ?? new();
    }

    public async Task SaveSiteAsync(Site site)
    {
        var module = await GetModuleAsync();
        var json = JsonSerializer.Serialize(site, JsonOptions);
        await module.InvokeVoidAsync("put", "sites", site.Id, json);
    }

    public async Task<List<Inspection>> GetInspectionsAsync(string? siteId = null)
    {
        var module = await GetModuleAsync();
        var json = await module.InvokeAsync<string>("getAll", "inspections");
        var all = JsonSerializer.Deserialize<List<Inspection>>(json, JsonOptions) ?? new();
        if (siteId is not null)
            all = all.Where(i => i.SiteId == siteId).ToList();
        return all.OrderByDescending(i => i.InspectionDate).ToList();
    }

    public async Task<Inspection?> GetInspectionAsync(string id)
    {
        var module = await GetModuleAsync();
        var json = await module.InvokeAsync<string?>("get", "inspections", id);
        return json is null ? null : JsonSerializer.Deserialize<Inspection>(json, JsonOptions);
    }

    public async Task SaveInspectionAsync(Inspection inspection)
    {
        var module = await GetModuleAsync();
        var json = JsonSerializer.Serialize(inspection, JsonOptions);
        await module.InvokeVoidAsync("put", "inspections", inspection.Id, json);
    }

    public async Task<List<Inspection>> GetUnsyncedInspectionsAsync()
    {
        var all = await GetInspectionsAsync();
        return all.Where(i => !i.IsSynced && i.Status == InspectionStatus.Completed).ToList();
    }

    public async Task MarkAsSyncedAsync(string inspectionId)
    {
        var inspection = await GetInspectionAsync(inspectionId);
        if (inspection is not null)
        {
            inspection.IsSynced = true;
            await SaveInspectionAsync(inspection);
        }
    }

    private static JsonSerializerOptions JsonOptions => new()
    {
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase
    };
}

using System.Net.Http.Json;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public class SyncService
{
    private readonly ILocalStorageService _storage;
    private readonly HttpClient _http;
    private bool _isSyncing;

    public event Action<string>? OnSyncStatusChanged;

    public SyncService(ILocalStorageService storage, HttpClient http)
    {
        _storage = storage;
        _http = http;
    }

    public async Task TrySyncAsync()
    {
        if (_isSyncing) return;
        _isSyncing = true;

        try
        {
            var unsynced = await _storage.GetUnsyncedInspectionsAsync();
            if (unsynced.Count == 0)
            {
                OnSyncStatusChanged?.Invoke("All data synced");
                return;
            }

            OnSyncStatusChanged?.Invoke($"Syncing {unsynced.Count} inspection(s)...");

            foreach (var inspection in unsynced)
            {
                try
                {
                    var response = await _http.PostAsJsonAsync("/api/inspections", inspection);
                    if (response.IsSuccessStatusCode)
                    {
                        await _storage.MarkAsSyncedAsync(inspection.Id);
                    }
                }
                catch (HttpRequestException)
                {
                    // Offline — stop trying
                    OnSyncStatusChanged?.Invoke($"Offline — {unsynced.Count} pending");
                    return;
                }
            }

            OnSyncStatusChanged?.Invoke("All data synced");
        }
        finally
        {
            _isSyncing = false;
        }
    }
}

