using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public class IndexedDbStorageService : ILocalStorageService
{
    private readonly IJSRuntime _js;
    private IJSObjectReference? _module;

    public IndexedDbStorageService(IJSRuntime js)
    {
        _js = js;
    }

    private async Task<IJSObjectReference> GetModuleAsync()
    {
        _module ??= await _js.InvokeAsync<IJSObjectReference>(
            "import", "./_content/SiteInspector.Client/js/indexedDb.js");
        return _module;
    }

    public async Task InitializeAsync()
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync("initialize");
    }

    public async Task<List<Site>> GetSitesAsync()
    {
        var module = await GetModuleAsync();
        var json = await module.InvokeAsync<string>("getAll", "sites");
        return JsonSerializer.Deserialize<List<Site>>(json, JsonOptions) ?? new();
    }

    public async Task SaveSiteAsync(Site site)
    {
        var module = await GetModuleAsync();
        var json = JsonSerializer.Serialize(site, JsonOptions);
        await module.InvokeVoidAsync("put", "sites", site.Id, json);
    }

    public async Task<List<Inspection>> GetInspectionsAsync(string? siteId = null)
    {
        var module = await GetModuleAsync();
        var json = await module.InvokeAsync<string>("getAll", "inspections");
        var all = JsonSerializer.Deserialize<List<Inspection>>(json, JsonOptions) ?? new();
        if (siteId is not null)
            all = all.Where(i => i.SiteId == siteId).ToList();
        return all.OrderByDescending(i => i.InspectionDate).ToList();
    }

