{"path": "/tmp/sv-1800b76fda754546922b4e928c27753b/SiteInspector/SiteInspector.Client/Services/SyncService.cs", "file_text": "using System.Net.Http.Json;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public class SyncService
{
    private readonly ILocalStorageService _storage;
    private readonly HttpClient _http;
    private bool _isSyncing;

    public event Action<string>? OnSyncStatusChanged;

    public SyncService(ILocalStorageService storage, HttpClient http)
    {
        _storage = storage;
        _http = http;
    }

    public async Task TrySyncAsync()
    {
        if (_isSyncing) return;
        _isSyncing = true;

        try
        {
            var unsynced = await _storage.GetUnsyncedInspectionsAsync();
            if (unsynced.Count == 0)
            {
                OnSyncStatusChanged?.Invoke("All data synced");
                return;
            }

            OnSyncStatusChanged?.Invoke($"Syncing {unsynced.Count} inspection(s)...");

            foreach (var inspection in unsynced)
            {
                try
                {
                    var response = await _http.PostAsJsonAsync("/api/inspections", inspection);
                    if (response.IsSuccessStatusCode)
                    {
                        await _storage.MarkAsSyncedAsync(inspection.Id);
                    }
                }
                catch (HttpRequestException)
                {
                    // Offline — stop trying
                    OnSyncStatusChanged?.Invoke($"Offline — {unsynced.Count} pending");
                    return;
                }
            }

            OnSyncStatusChanged?.Invoke("All data synced");
        }
        finally
        {
            _isSyncing = false;
        }
    }
}
"}

