const DB_NAME = 'SiteInspectorDb';
const DB_VERSION = 1;

let db = null;

export async function initialize() {
    if (db) return;
    return new Promise((resolve, reject) => {
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (e) => {
            const database = e.target.result;
            if (!database.objectStoreNames.contains('sites')) {
                database.createObjectStore('sites', { keyPath: 'id' });
            }
            if (!database.objectStoreNames.contains('inspections')) {
                database.createObjectStore('inspections', { keyPath: 'id' });
            }
        };
        request.onsuccess = (e) => {
            db = e.target.result;
            resolve();
        };
        request.onerror = (e) => reject(e.target.error);
    });
}

export async function put(storeName, key, jsonValue) {
    await initialize();
    const obj = JSON.parse(jsonValue);
    return new Promise((resolve, reject) => {
        const tx = db.transaction(storeName, 'readwrite');
        const store = tx.objectStore(storeName);
        // Ensure the key field matches
        obj.id = key;
        store.put(obj);
        tx.oncomplete = () => resolve();
        tx.onerror = (e) => reject(e.target.error);
    });
}

export async function get(storeName, key) {
    await initialize();
    return new Promise((resolve, reject) => {
        const tx = db.transaction(storeName, 'readonly');
        const store = tx.objectStore(storeName);
        const request = store.get(key);
        request.onsuccess = () => {
            resolve(request.result ? JSON.stringify(request.result) : null);
        };
        request.onerror = (e) => reject(e.target.error);
    });
}

export async function getAll(storeName) {
    await initialize();
    return new Promise((resolve, reject) => {
        const tx = db.transaction(storeName, 'readonly');
        const store = tx.objectStore(storeName);
        const request = store.getAll();
        request.onsuccess = () => {
            resolve(JSON.stringify(request.result || []));
        };
        request.onerror = (e) => reject(e.target.error);
    });
}

export async function remove(storeName, key) {
    await initialize();
    return new Promise((resolve, reject) => {
        const tx = db.transaction(storeName, 'readwrite');
        const store = tx.objectStore(storeName);
        store.delete(key);
        tx.oncomplete = () => resolve();
        tx.onerror = (e) => reject(e.target.error);
    });
}

