@inherits LayoutComponentBase

<div class="app-container">
    <header class="app-header">
        <div class="header-content">
            <a href="/" class="header-title">
                <span class="header-icon">🏗️</span>
                <span>Site Inspector</span>
            </a>
            <div class="sync-indicator">
                <span class="@(_isOnline ? "status-online" : "status-offline")">
                    @(_isOnline ? "●" : "○")
                </span>
            </div>
        </div>
    </header>

    <main class="app-main">
        @Body
    </main>
</div>

@code {
    private bool _isOnline = true;

    [Inject] private IJSRuntime JS { get; set; } = default!;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _isOnline = await JS.InvokeAsync<bool>("eval", "navigator.onLine");
            StateHasChanged();
        }
    }
}

.app-container {
    display: flex;
    flex-direction: column;
    min-height: 100dvh;
    background: #f5f5f5;
}

.app-header {
    background: #1a1a2e;
    color: white;
    padding: 0.75rem 1rem;
    position: sticky;
    top: 0;
    z-index: 100;
    box-shadow: 0 2px 8px rgba(0,0,0,0.2);
}

.header-content {
    display: flex;
    align-items: center;
    justify-content: space-between;
    max-width: 600px;
    margin: 0 auto;
}

.header-title {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    color: white;
    text-decoration: none;
    font-size: 1.1rem;
    font-weight: 600;
}

.header-icon {
    font-size: 1.4rem;
}

.sync-indicator {
    font-size: 1.2rem;
}

.status-online {
    color: #4caf50;
}

.status-offline {
    color: #ff9800;
}

.app-main {
    flex: 1;
    padding: 1rem;
    max-width: 600px;
    margin: 0 auto;
    width: 100%;
}

