arguments.new_str:
@page "/"
@using SiteInspector.Client.Models
@using SiteInspector.Client.Services
@inject ILocalStorageService Storage
@inject SyncService Sync
@inject NavigationManager Nav

<PageTitle>Site Inspector</PageTitle>

<div class="page-header">
    <h1>Construction Sites</h1>
    <button class="btn-sync" @onclick="TrySyncAsync">
        🔄 Sync
    </button>
</div>

@if (!string.IsNullOrEmpty(_syncStatus))
{
    <div class="sync-banner">@_syncStatus</div>
}

@if (_showAddSite)
{
    <div class="card add-site-form">
        <input @bind="_newSiteName" @bind:event="oninput" placeholder="Site name" class="input" />
        <input @bind="_newSiteAddress" @bind:event="oninput" placeholder="Address" class="input" />
        <div class="form-actions">
            <button class="btn btn-primary" @onclick="AddSiteAsync" disabled="@string.IsNullOrWhiteSpace(_newSiteName)">
                Add Site
            </button>
            <button class="btn btn-secondary" @onclick="() => _showAddSite = false">Cancel</button>
        </div>
    </div>
}

<div class="site-list">
    @if (_sites.Count == 0)
    {
        <div class="empty-state">
            <p>No sites yet. Add your first construction site to begin inspections.</p>
        </div>
    }

    @foreach (var site in _sites)
    {
        <div class="site-card" @onclick="() => Nav.NavigateTo($"/site/{site.Id}")">
            <div class="site-info">
                <h3>@site.Name</h3>
                <p>@site.Address</p>
            </div>
            <span class="chevron">›</span>
        </div>
    }
</div>

<button class="fab" @onclick="() => _showAddSite = true">＋</button>

@code {
    private List<Site> _sites = new();
    private bool _showAddSite;
    private string _newSiteName = "";
    private string _newSiteAddress = "";
    private string _syncStatus = "";

    protected override async Task OnInitializedAsync()
    {
        await Storage.InitializeAsync();
        _sites = await Storage.GetSitesAsync();
        Sync.OnSyncStatusChanged += OnSyncStatus;
    }

    private async Task AddSiteAsync()
    {
        var site = new Site { Name = _newSiteName, Address = _newSiteAddress };
        await Storage.SaveSiteAsync(site);
        _sites.Insert(0, site);
        _newSiteName = "";
        _newSiteAddress = "";
        _showAddSite = false;
    }

    private async Task TrySyncAsync()
    {
        _syncStatus = "Checking...";
        await Sync.TrySyncAsync();
    }

    private void OnSyncStatus(string status)
    {
        _syncStatus = status;
        InvokeAsync(StateHasChanged);
    }
}

