@page "/site/{SiteId}"
@using SiteInspector.Client.Models
@using SiteInspector.Client.Services
@inject ILocalStorageService Storage
@inject NavigationManager Nav

<PageTitle>@_site?.Name</PageTitle>

<div class="page-header">
    <button class="btn-back" @onclick='() => Nav.NavigateTo("/")'>← Back</button>
    <h1>@(_site?.Name ?? "Loading...")</h1>
</div>

@if (_site is not null)
{
    <p class="site-address">📍 @_site.Address</p>

    <h2 class="section-title">Inspections</h2>

    <div class="inspection-list">
        @if (_inspections.Count == 0)
        {
            <div class="empty-state">
                <p>No inspections yet. Start your first one!</p>
            </div>
        }

        @foreach (var inspection in _inspections)
        {
            <div class="inspection-card" @onclick="() => Nav.NavigateTo($"/inspection/{inspection.Id}")">
                <div class="inspection-info">
                    <div class="inspection-date">@inspection.InspectionDate.ToString("MMM dd, yyyy h:mm tt")</div>
                    <div class="inspection-meta">
                        <span class="badge @(inspection.Status == InspectionStatus.Completed ? "badge-done" : "badge-progress")">
                            @(inspection.Status == InspectionStatus.Completed ? "✓ Done" : "● In Progress")
                        </span>
                        @if (!inspection.IsSynced)
                        {
                            <span class="badge badge-pending">⏳ Not synced</span>
                        }
                    </div>
                </div>
                <span class="chevron">›</span>
            </div>
        }
    </div>

    <button class="fab" @onclick="StartNewInspection">＋</button>
}

@code {
    [Parameter] public string SiteId { get; set; } = "";

    private Site? _site;
    private List<Inspection> _inspections = new();

    protected override async Task OnInitializedAsync()
    {
        await Storage.InitializeAsync();
        var sites = await Storage.GetSitesAsync();
        _site = sites.FirstOrDefault(s => s.Id == SiteId);
        _inspections = await Storage.GetInspectionsAsync(SiteId);
    }

    private async Task StartNewInspection()
    {
        var inspection = new Inspection
        {
            SiteId = SiteId,
            SiteName = _site?.Name ?? "",
            Checklist = ChecklistTemplateService.GetDefaultChecklist()
        };
        await Storage.SaveInspectionAsync(inspection);
        Nav.NavigateTo($"/inspection/{inspection.Id}");
    }
}

