@page "/inspection/{InspectionId}"
@using SiteInspector.Client.Models
@using SiteInspector.Client.Services
@inject ILocalStorageService Storage
@inject NavigationManager Nav
@inject IJSRuntime JS

<PageTitle>Inspection</PageTitle>

<div class="page-header">
    <button class="btn-back" @onclick="GoBack">← Back</button>
    <h1>Inspection</h1>
    @if (_inspection?.Status == InspectionStatus.InProgress)
    {
        <button class="btn-complete" @onclick="CompleteInspection">✓ Complete</button>
    }
    else
    {
        <span class="status-done">✓ Completed</span>
    }
</div>

@if (_inspection is not null)
{
    <div class="tab-bar">
        <button class="tab @(_activeTab == "checklist" ? "active" : "")" @onclick='() => _activeTab = "checklist"'>
            Checklist
        </button>
        <button class="tab @(_activeTab == "photos" ? "active" : "")" @onclick='() => _activeTab = "photos"'>
            Photos (@_inspection.Photos.Count)
        </button>
        <button class="tab @(_activeTab == "notes" ? "active" : "")" @onclick='() => _activeTab = "notes"'>
            Notes
        </button>
    </div>

    @if (_activeTab == "checklist")
    {
        <div class="checklist">
            @foreach (var category in _inspection.Checklist.GroupBy(c => c.Category))
            {
                <div class="category-section">
                    <h3 class="category-title">@category.Key</h3>
                    @foreach (var item in category)
                    {
                        <div class="checklist-item">
                            <div class="item-desc">@item.Description</div>
                            <div class="item-actions">
                                <button class="result-btn @(item.Result == CheckResult.Pass ? "selected-pass" : "")"
                                        @onclick="() => SetResult(item, CheckResult.Pass)">✓</button>
                                <button class="result-btn @(item.Result == CheckResult.Fail ? "selected-fail" : "")"
                                        @onclick="() => SetResult(item, CheckResult.Fail)">✗</button>
                                <button class="result-btn @(item.Result == CheckResult.NotApplicable ? "selected-na" : "")"
                                        @onclick="() => SetResult(item, CheckResult.NotApplicable)">N/A</button>
                            </div>
                            @if (item.Result == CheckResult.Fail)
                            {
                                <input class="item-note" placeholder="Note (required for failures)"
                                       value="@item.Notes"
                                       @onchange="(e) => SetItemNote(item, e.Value?.ToString() ?? "")" />
                            }
                        </div>
                    }
                </div>
            }
        </div>

        <div class="progress-bar">
            <div class="progress-fill" style="width: @ProgressPercent%"></div>
        </div>
        <div class="progress-text">@CompletedCount / @_inspection.Checklist.Count checked</div>
    }
    else if (_activeTab == "photos")
    {
        <div class="photos-section">
            <label class="photo-capture-btn">
                📷 Take Photo
                <InputFile OnChange="OnPhotoSelected" accept="image/*" capture="environment" class="hidden-input" />
            </label>

            <div class="photo-grid">
                @foreach (var photo in _inspection.Photos)
                {
                    <div class="photo-card">
                        <img src="@($"data:image/jpeg;base64,{photo.Base64Data}")" alt="@photo.Caption" />
                        <input class="photo-caption" placeholder="Add caption..."
                               value="@photo.Caption"
                               @onchange="(e) => SetPhotoCaption(photo, e.Value?.ToString() ?? "")" />
                    </div>
                }
            </div>

            @if (_inspection.Photos.Count == 0)
            {
                <div class="empty-state">
                    <p>No photos yet. Tap the button above to capture site photos.</p>
                </div>
            }
        </div>
    }
    else if (_activeTab == "notes")
    {
        <div class="notes-section">
            <textarea class="notes-input" placeholder="Add inspection notes, observations, concerns..."
                      @bind="_inspection.Notes" @bind:event="oninput" rows="10"></textarea>
            <button class="btn btn-primary" @onclick="SaveAsync">Save Notes</button>
        </div>
    }
}

